from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
import ast

app = Flask(__name__)
es = Elasticsearch([{'host': 'localhost', 'port': 9200}]) # assuming you're running your ES instance on localhost and default port (9200)

@app.route('/run_script', methods=['POST'])
def run_script():
    data = request.get_json()
    
    if 'script' not in data:
        return jsonify({"error": "Missing script parameter."}), 400
    
    # convert user-inputted script to Python dictionary, assuming the JSON provided is valid. This would be your dynamic script
    try:
        script = ast.literal_eval(data['script'])
    except Exception as e:
        return jsonify({"error": "Invalid script."}), 400
    
    # Elasticsearch DSL not used here, instead raw requests to ES are executed directly for simplicity and because the official library lacks support for inline scripts.
    try:
        res = es.search(body={
            "query": {
                "function_score": {
                    "functions": [
                        {"inline": script}
                    ],
                    "script_score": {}
                }
            }
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    
    return jsonify(res), 200

if __name__ == '__main__':
    app.run()